from http.server import BaseHTTPRequestHandler
import json, io, base64, os, tempfile, shutil, subprocess
from datetime import date, datetime

VOUCHER_PPTX_B64 = ""
CONF_XLSX_B64    = ""


def _fmtd(d):
    if not d: return ""
    s = str(d)[:10]
    if "-" in s:
        p = s.split("-")
        return f"{p[2]}/{p[1]}/{p[0][-2:]}"
    return s

def _fmtd_full(d):
    if not d: return ""
    s = str(d)[:10]
    if "-" in s:
        p = s.split("-")
        return f"{p[2]}/{p[1]}/{p[0]}"
    return s

def _noches(a, b):
    try:
        return (datetime.fromisoformat(str(b)[:10]) - datetime.fromisoformat(str(a)[:10])).days
    except: return 0

def _pax_voucher(r):
    p = []
    if r.get("adultos"): p.append(f"Adl: {r['adultos']}")
    if r.get("chd"):     p.append(f"Chd: {r['chd']}")
    if r.get("inf"):     p.append(f"Inf: {r['inf']}")
    return " / ".join(p)

def _pax_conf(r):
    p = []
    if r.get("adultos"): p.append(f"Adultos: {r['adultos']}")
    if r.get("chd"):     p.append(f"Menores: {r['chd']}")
    if r.get("inf"):     p.append(f"Infantes: {r['inf']}")
    return "  /  ".join(p)

def _to_pdf(src_path, outdir):
    """Convierte PPTX o XLSX a PDF usando LibreOffice."""
    soffice = os.path.join(os.path.dirname(__file__), "soffice_helper.py")
    # Buscar soffice disponible
    for soff in ["soffice", "libreoffice", "/usr/bin/soffice", "/usr/bin/libreoffice"]:
        if shutil.which(soff):
            subprocess.run(
                [soff, "--headless", "--convert-to", "pdf", "--outdir", outdir, src_path],
                capture_output=True, timeout=60
            )
            break
    base = os.path.splitext(os.path.basename(src_path))[0]
    return os.path.join(outdir, base + ".pdf")


def gen_voucher_pdf(r):
    from pptx import Presentation

    tmp = tempfile.mkdtemp()
    try:
        pptx_path = os.path.join(tmp, "voucher.pptx")
        with open(pptx_path, "wb") as f:
            f.write(base64.b64decode(VOUCHER_PPTX_B64))

        prs = Presentation(pptx_path)
        slide = prs.slides[0]

        hoy     = date.today().strftime("%d/%m/%y")
        hotel   = (r.get("proveedor_nombre") or r.get("destino","")).upper()
        codigo  = r.get("cod_proveedor","") or ""
        servicio = ", ".join(filter(None,[r.get("habitacion",""), r.get("regimen","")]))
        benef   = f"{r.get('pasajero_nombre','')} ({_pax_voucher(r)})"
        nn      = _noches(r.get("fecha_in"), r.get("fecha_out"))

        MAPA = {
            "Google Shape;56;p13": hoy,
            "Google Shape;58;p13": servicio,
            "Google Shape;59;p13": benef,
            "Google Shape;62;p13": _fmtd(r.get("fecha_in")),
            "Google Shape;63;p13": _fmtd(r.get("fecha_out")),
            "Google Shape;64;p13": f"({nn} noches)",
            "Google Shape;67;p13": hotel,
            "Google Shape;68;p13": codigo,
        }

        for shape in slide.shapes:
            if shape.name in MAPA and shape.has_text_frame:
                nuevo = MAPA[shape.name]
                tf = shape.text_frame
                for i, para in enumerate(tf.paragraphs):
                    for j, run in enumerate(para.runs):
                        run.text = nuevo if (i == 0 and j == 0) else ""
                    if i > 0:
                        for run in para.runs:
                            run.text = ""

        prs.save(pptx_path)

        for soff in ["soffice", "libreoffice", "/usr/bin/soffice", "/usr/bin/libreoffice"]:
            if shutil.which(soff):
                subprocess.run(
                    [soff, "--headless", "--convert-to", "pdf", "--outdir", tmp, pptx_path],
                    capture_output=True, timeout=60
                )
                break

        pdf_path = os.path.join(tmp, "voucher.pdf")
        with open(pdf_path, "rb") as f:
            return f.read()
    finally:
        shutil.rmtree(tmp, ignore_errors=True)


def gen_confirmacion_pdf(r):
    import openpyxl

    tmp = tempfile.mkdtemp()
    try:
        xlsx_path = os.path.join(tmp, "conf.xlsx")
        with open(xlsx_path, "wb") as f:
            f.write(base64.b64decode(CONF_XLSX_B64))

        wb = openpyxl.load_workbook(xlsx_path)
        ws = wb.active

        hotel = r.get("proveedor_nombre") or r.get("destino","")
        total = f"{r.get('moneda','USD')} {int(r['venta'])}.-" if r.get("venta") else "-"
        nn    = _noches(r.get("fecha_in"), r.get("fecha_out"))

        ws["J4"]  = date.today().strftime("%d/%m/%Y")
        ws["C14"] = hotel
        ws["D16"] = r.get("pasajero_nombre","")
        ws["D18"] = _pax_conf(r)
        ws["D19"] = _fmtd_full(r.get("fecha_in"))
        ws["G20"] = nn
        ws["D21"] = _fmtd_full(r.get("fecha_out"))
        ws["D23"] = r.get("habitacion","-") or "-"
        ws["D25"] = r.get("regimen","N/A") or "N/A"
        ws["D27"] = total

        wb.save(xlsx_path)

        for soff in ["soffice", "libreoffice", "/usr/bin/soffice", "/usr/bin/libreoffice"]:
            if shutil.which(soff):
                subprocess.run(
                    [soff, "--headless", "--convert-to", "pdf", "--outdir", tmp, xlsx_path],
                    capture_output=True, timeout=60
                )
                break

        pdf_path = os.path.join(tmp, "conf.pdf")
        with open(pdf_path, "rb") as f:
            return f.read()
    finally:
        shutil.rmtree(tmp, ignore_errors=True)


class handler(BaseHTTPRequestHandler):
    def do_POST(self):
        try:
            length = int(self.headers.get("Content-Length", 0))
            body   = json.loads(self.rfile.read(length))
            tipo   = body.get("tipo")
            r      = body.get("reserva", {})

            if not tipo or not r:
                self._respond(400, {"error": "Faltan campos"})
                return

            nombre = r.get("pasajero_nombre","")
            hotel  = r.get("proveedor_nombre") or r.get("destino","")

            if tipo == "voucher":
                pdf   = gen_voucher_pdf(r)
                fname = f"Voucher_{nombre.replace(' ','_')}.pdf"
                subj  = f"Voucher de viaje — {hotel}"
            else:
                pdf   = gen_confirmacion_pdf(r)
                fname = f"Confirmacion_{nombre.replace(' ','_')}.pdf"
                subj  = f"Confirmacion de reserva — {hotel}"

            self._respond(200, {
                "ok":       True,
                "pdf":      base64.b64encode(pdf).decode(),
                "filename": fname,
                "subject":  subj,
                "nombre":   nombre,
            })

        except Exception as e:
            import traceback
            self._respond(500, {"error": str(e), "trace": traceback.format_exc()})

    def _respond(self, code, data):
        body = json.dumps(data).encode()
        self.send_response(code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", len(body))
        self.end_headers()
        self.wfile.write(body)

    def log_message(self, *args):
        pass
